// Prepare documents for embedding
const trigger = $input.first().json;
const projectId = trigger.project_id;
const userId = trigger.user_id || '';

const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const readHeaders = { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY };
const writeHeaders = { ...readHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' };

if (!projectId) return [{ json: { error: true, result: 'No project_id provided' } }];

// Load project
const projResp = await this.helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/writing_projects_v2?id=eq.' + projectId + '&select=id,title,genre_slug,outline&user_id=eq.' + encodeURIComponent(userId),
  headers: readHeaders
});
const project = projResp[0];
if (!project || !project.outline) return [{ json: { error: true, result: 'Project not found or no outline' } }];
const outline = project.outline;

// Load story bible
const bible = await this.helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/story_bible_v2?project_id=eq.' + projectId + '&user_id=eq.' + encodeURIComponent(userId) + '&select=id,entry_type,name,description,chapter_introduced,last_chapter_seen',
  headers: readHeaders
});

// Load genre
let genreConfig = {};
if (project.genre_slug) {
  const g = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/genre_config_v2?genre_slug=eq.' + encodeURIComponent(project.genre_slug) + '&limit=1',
    headers: readHeaders
  });
  if (g && g.length > 0) genreConfig = g[0];
}

// Build documents
const docs = [];

for (const char of (outline.characters || [])) {
  docs.push({
    doc_type: 'character', doc_id: char.name,
    doc_title: char.name + ' (' + char.role + ')',
    content: 'Character: ' + char.name + '\nRole: ' + char.role + '\nArc: ' + char.arc + (char.description ? '\nDescription: ' + char.description : '')
  });
}

for (const ch of (outline.chapters || [])) {
  docs.push({
    doc_type: 'chapter_brief', doc_id: 'ch_' + ch.number,
    doc_title: 'Ch ' + ch.number + ' — ' + ch.title,
    content: 'Chapter ' + ch.number + ': ' + ch.title + '\nBrief: ' + ch.brief + (ch.arc_notes ? '\nArc Notes: ' + ch.arc_notes : '')
  });
  if (ch.chapter_outline && ch.chapter_outline.sub_chapters) {
    for (const sc of ch.chapter_outline.sub_chapters) {
      docs.push({
        doc_type: 'sub_chapter', doc_id: 'ch' + ch.number + '_sc' + sc.number,
        doc_title: 'Ch' + ch.number + ' Sub' + sc.number + ': ' + sc.title,
        content: 'Sub-chapter ' + sc.number + ' of Chapter ' + ch.number + ': ' + sc.title + '\nBrief: ' + sc.brief + '\nArc Beat: ' + (sc.arc_beat || '') + '\nCharacters: ' + (sc.characters || []).join(', ')
      });
    }
  }
}

for (const entry of bible) {
  docs.push({
    doc_type: 'bible_entry', doc_id: entry.id,
    doc_title: '[' + entry.entry_type + '] ' + entry.name,
    content: entry.entry_type + ': ' + entry.name + '\nDescription: ' + entry.description + '\nIntroduced: Chapter ' + entry.chapter_introduced
  });
}

if (genreConfig.genre_name) {
  docs.push({
    doc_type: 'genre_config', doc_id: project.genre_slug,
    doc_title: 'Genre: ' + genreConfig.genre_name,
    content: 'Genre: ' + genreConfig.genre_name + '\nDescription: ' + (genreConfig.description || '') + '\nStyle: ' + (genreConfig.style_notes || '')
  });
}

if (outline.premise) {
  docs.push({
    doc_type: 'premise', doc_id: 'premise',
    doc_title: 'Book Premise',
    content: 'Premise: ' + outline.premise + '\nThemes: ' + (outline.themes || []).join(', ')
  });
}

if (outline.story_arc_name) {
  docs.push({
    doc_type: 'book_arc', doc_id: 'book_arc',
    doc_title: 'Book Story Arc: ' + outline.story_arc_name,
    content: 'Story Arc: ' + outline.story_arc_name
  });
}

// Delete old embeddings
await this.helpers.httpRequest({
  method: 'DELETE',
  url: SUPABASE_URL + '/rest/v1/writing_embeddings_v2?project_id=eq.' + projectId + '&user_id=eq.' + encodeURIComponent(userId),
  headers: readHeaders
});

// Output all docs as separate items for batching
return docs.map(d => ({ json: { ...d, project_id: projectId, user_id: userId, project_title: project.title, total_docs: docs.length } }));

// Save all embeddings to Supabase
const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const headers = { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' };

const items = $input.all();
const prepItems = $('prepare_documents').all();
let saved = 0;

// Batch insert in groups of 20
const rows = [];
for (let i = 0; i < items.length; i++) {
  const embData = items[i].json.data ? items[i].json.data[0] : items[i].json;
  const doc = prepItems[i].json;
  if (!embData.embedding) continue;
  rows.push({
    user_id: doc.user_id,
    project_id: doc.project_id,
    doc_type: doc.doc_type,
    doc_id: doc.doc_id,
    doc_title: doc.doc_title,
    content: doc.content,
    metadata: {},
    embedding: JSON.stringify(embData.embedding)
  });
}

for (let i = 0; i < rows.length; i += 20) {
  const batch = rows.slice(i, i + 20);
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/writing_embeddings_v2',
    headers,
    body: JSON.stringify(batch)
  });
  saved += batch.length;
}

return [{ json: { result: 'Saved ' + saved + ' embeddings', saved_count: saved } }];

